SHARED VARIABLES:
  flag[0] : BOOLEAN := FALSE
  flag[1] : BOOLEAN := FALSE
  turn : INTEGER := 0

// Process 0
WHILE TRUE DO
  flag[0] := TRUE
  turn := 1
  WHILE (flag[1] AND turn = 1) DO
    // busy wait - critical section entry condition
  END WHILE

  // CRITICAL SECTION
  // ... shared code ...

  flag[0] := FALSE
  // REMAINDER SECTION
END WHILE

// Process 1 is symmetric with indices swapped
